
import { ref, reactive, onMounted, nextTick } from 'vue';
import { List, PullRefresh,Loading } from 'vant'
import api from './service/api'
import { parseTime2, getUrlParam1 } from '@/utils/index';
import { getyyyymmdd } from '../../utils/time';
export default {
  name: 'trackDetail',
  components: {
    'List':List,
    'van-pull-refresh':PullRefresh,
    'van-loading':Loading,
  },
  setup () {
    const myForm = reactive({
      refreshing: false,
      loading: false,
      listLoading: false,
      lastDomNum:1
    })
    const list = ref([]) as any
    const allList = ref([])
    const time = new Date().getTime()
    const has_more = ref(true)
    const today = getyyyymmdd(time)
    const yesterDay = getyyyymmdd(time - 24 * 60 * 60 * 1000)
    let nowDate = ''
    let last_time = 0
    const handelList = (mylist:any)=>{
      let item0 = {} as any
      const newList = []
      for(let i=0;i<mylist.length;i++){
        const item = mylist[i]
        // 判断如果enter_page_type为0一级则展示否则放到上一条数据children中
        if(item.enter_page_type===0){
          item0 = item
          item.children = []
        }else{
          if(!item0.children) {
            item.children = [{using_type:item.using_type,name:item.name,time:item.time}]
            item.enter_page_type = 0
            item.name = ''
            item.zi = true
            item0 = item
          }else{
            item0.children.push(item)
            continue
          }
        }
        newList.push(item)
      }
      console.log(newList)
      for(let i=newList.length-1;i>=0;i--){
        const item = newList[i]
        // 处理遇到不同日期增加日期标题
        if(parseTime2(nowDate,'{y}-{m}-{d}')!==parseTime2(item.time,'{y}-{m}-{d}')) {
          const myDate = getyyyymmdd(item.time)
          if (myDate === today) {
            item.dateTitle = '今天'
          } else if (myDate === yesterDay) {
            item.dateTitle = '昨天'
          } else {
            item.dateTitle = parseTime2(item.time,'{m}月{d}日')
          }
        }
        // 处理遇到分页时断点出日期相同，把之前日期标题清除，赋值最新日期标题
        if(list.value.length>0&&parseTime2(item.time,'{y}-{m}-{d}') === parseTime2(list.value[0].time,'{y}-{m}-{d}')){
          list.value[0].dateTitle = ''
          const myDate = getyyyymmdd(item.time)
          if (myDate === today) {
            item.dateTitle = '今天'
          } else if (myDate === yesterDay) {
            item.dateTitle = '昨天'
          } else {
            item.dateTitle = parseTime2(item.time,'{m}月{d}日')
          }
        }
        nowDate = item.time
        // 如何当前数据时间和上一组数据的第一条时间一样，则把上一组数据第一条日期清除

        // 处理图片和描述
        switch(item.type){
          case 1:
            item.url = 'https://static0.xesimg.com/xpp-parent-fe/trackDetail/xt.png'
            item.desc = '学习机'
            break
          case 2:
            item.url = 'https://static0.xesimg.com/xpp-parent-fe/trackDetail/kc.png'
            item.desc = '进入课程'
            break
          case 3:
            item.url = 'https://static0.xesimg.com/xpp-parent-fe/trackDetail/gj.png'
            item.desc = '进入'
            break
          case 4:
            item.url = 'https://static0.xesimg.com/xpp-parent-fe/trackDetail/sy.png'
            item.desc = '进入'
            break
          case 5:
            item.url = 'https://static0.xesimg.com/xpp-parent-fe/trackDetail/yy.png'
            item.desc = '进入'
            break
        }
        // 单独子轨迹不展示描述
        if(item.zi) {
          item.desc = ''
        }
        list.value.unshift(item)
      }
      console.log(list.value)
    }
    // 配置列表
    const getTrackList = async (init:boolean)=>{
      const tal_id = getUrlParam1('tal_id') || ''
      try{
        const res:any = await api.getTrackList({ last_time:last_time,tal_id: tal_id,page_size:20})
        // const res:any = await api.getTrackList({ token:'tal173lbO8YBE1MGvfJdTuxwN8ipqcvdhnrplP6eaarwrd90KA-ZytoZTEG6bERNoWOm8caT341ADYLg0EaA2_ZpICV-x1VegoPrP-SHzdwnZ_0z6guDFjCzsRW-L4l4yhqQ4bWvPM-ZINnK6L977VSAP1eJ5oOo-r4acP7YrJC11og-sfh',last_time:last_time,tal_id: 'TalofEXlRv7HoNFpRxcoVSjXzQ',page_size:100})
        myForm.refreshing = false
        myForm.loading = false
        if (res.data.errcode === 0 && res.data.data ) {
          has_more.value = res.data.data.has_more
          if(res.data.data.list&&res.data.data.list.length>0){
            allList.value = allList.value.concat(res.data.data.list)
            last_time = res.data.data.list[0].time
            handelList(res.data.data.list)
          }
        }
        if(init){
          nextTick(()=>{
            window.scrollTo(0, document.body.scrollHeight)
          })
        }else{
          setTimeout(()=>{
            const dom = (document.querySelector('.my-list') as any).querySelectorAll('.my-item')
            const dom1 = dom[dom.length-myForm.lastDomNum]
            // 距离滚动条顶部距离
            window.scrollTo(0,  dom1.offsetTop-55)
          })
        }
      }catch (e){
        myForm.refreshing = false
        myForm.loading = false
      }
    }
    const onRefresh = ()=>{
      myForm.loading = true
      myForm.refreshing = true
      // 大于2000条数据就不再请求
      if(allList.value.length>2000){
        has_more.value = false
      }
      if(has_more.value||last_time) {
        myForm.lastDomNum =  (document.querySelector('.my-list') as any).querySelectorAll('.my-item').length||1
        getTrackList(false)
      }else{
        myForm.refreshing = false
        myForm.loading = false
      }
    }
    onMounted(()=>{
      getTrackList(true)
    })
    return {
      myForm,
      onRefresh,
      parseTime2,
      list,
      has_more
    }
  }
}
